mapper.update:
update lockers
set status = #{status}
where locker_id = #{lockerId};

mapper.select:
select locker_id, school_id, status, created_at, updated_at
from lockers
where school_id = #{schoolId};

select locker_id, school_id, status, created_at, updated_at
from lockers
where school_id = #{schoolId}
  and status = '0'
limit 1
for update;
